<?php
/** Sustainable Catalyst Lab v0.28.1 Dataset Registry and Scientific Data Management. */
if (!defined('ABSPATH')) { exit; }
final class SC_Lab_Dataset_Registry_V0281 {
    const VERSION='0.28.1';
    private static $initialized=false;
    public static function init(){if(self::$initialized){return;}self::$initialized=true;add_action('rest_api_init',array(__CLASS__,'routes'));add_filter('sc_lab_module_aliases_v02631',array(__CLASS__,'aliases'));}
    public static function aliases($aliases){$aliases=is_array($aliases)?$aliases:array();foreach(array('dataset-registry','data-registry','scientific-data','dataset-management') as $alias){$aliases[$alias]='dataset-registry';}return $aliases;}
    public static function routes(){register_rest_route('sc-lab/v1','/datasets/v0281/health',array('methods'=>WP_REST_Server::READABLE,'callback'=>array(__CLASS__,'health'),'permission_callback'=>'__return_true'));register_rest_route('sc-lab/v1','/datasets/v0281/schema',array('methods'=>WP_REST_Server::READABLE,'callback'=>array(__CLASS__,'schema'),'permission_callback'=>'__return_true'));register_rest_route('sc-lab/v1','/datasets/v0281/formats',array('methods'=>WP_REST_Server::READABLE,'callback'=>array(__CLASS__,'formats'),'permission_callback'=>'__return_true'));}
    private static function state($relative){$path=SC_LAB_DIR.$relative;return array('exists'=>is_file($path),'sha256'=>is_file($path)?hash_file('sha256',$path):null);}
    public static function schema(){return rest_ensure_response(array('ok'=>true,'version'=>self::VERSION,'schema'=>'sc-lab-dataset-registry/0.28.1','projectWorkspace'=>'0.28.0','storage'=>'browser-local','serverBackedRegistry'=>false,'canonicalRecordType'=>'dataset','capabilities'=>array('dataDictionary'=>true,'variableUnits'=>true,'validationStatus'=>true,'sourceMetadata'=>true,'licenseMetadata'=>true,'lineage'=>true,'profiling'=>true,'projectRegistry'=>true,'import'=>array('csv'=>'full','json'=>'full','geojson'=>'full','netcdf'=>'metadata-only'))));}
    public static function formats(){ $path=SC_LAB_DIR.'contracts/dataset-formats-v0281.json';$decoded=is_file($path)?json_decode((string)file_get_contents($path),true):null;return rest_ensure_response(is_array($decoded)?array_merge(array('ok'=>true),$decoded):array('ok'=>false,'version'=>self::VERSION,'formats'=>array()));}
    public static function health(){ $required=array('assets/js/modules/datasets.js','assets/js/modules/dataset-registry-v0281.js','assets/css/sc-lab-dataset-registry-v0281.css','contracts/dataset-registry-v0281.schema.json','contracts/dataset-profile-v0281.schema.json','contracts/dataset-bundle-v0281.schema.json','contracts/dataset-formats-v0281.json','includes/class-sc-lab-dataset-registry-v0281.php');$files=array();foreach($required as $rel){$files[$rel]=self::state($rel);} $ok=!in_array(false,array_map(function($row){return !empty($row['exists']);},$files),true);return rest_ensure_response(array('ok'=>$ok,'status'=>$ok?'ready':'incomplete','version'=>self::VERSION,'release'=>defined('SC_LAB_VERSION')?SC_LAB_VERSION:null,'architecture'=>'browser-local-dataset-registry','projectWorkspace'=>'0.28.0','supportedFormats'=>array('csv','json','geojson','netcdf','tabular'),'pythonProfiling'=>true,'serverBackedRegistry'=>false,'files'=>$files,'time'=>gmdate('c')));}
}
